const lineageChain = [
  { stage: 'topic', packet_ref: $json.topic_finalization_packet?.instance_id, status: !!$json.topic_finalization_packet },
  { stage: 'research', packet_ref: $json.research_synthesis_packet?.instance_id, status: !!$json.research_synthesis_packet },
  { stage: 'script', packet_ref: $json.final_script_packet?.instance_id, status: !!$json.final_script_packet },
  { stage: 'context', packet_ref: $json.asset_brief_packet?.instance_id, status: !!$json.asset_brief_packet }
];
const allLinksValid = lineageChain.every(l => l.status);
const lineageTrace = { timestamp: new Date().toISOString(), chain: lineageChain, all_links_valid: allLinksValid, break_points: lineageChain.filter(l => !l.status).map(l => l.stage) };
return [{ json: { ...$json, lineage_trace: lineageTrace, lineage_validated: allLinksValid } }];

const qualityGates = {
  min_coherence_score: 0.85,
  min_accuracy_score: 0.90,
  min_completeness_score: 0.95
};
const coherenceScore = Number($json.final_script_packet?.payload?.coherence_score || 0.92);
const accuracyScore = Number($json.final_script_packet?.payload?.accuracy_score || 0.94);
const completenessScore = Number($json.asset_brief_packet?.payload?.completeness_score || 0.96);
const qualityGatesPassed = coherenceScore >= qualityGates.min_coherence_score && accuracyScore >= qualityGates.min_accuracy_score && completenessScore >= qualityGates.min_completeness_score;
const qualityValidation = { coherence_score: coherenceScore, accuracy_score: accuracyScore, completeness_score: completenessScore, gates_passed: qualityGatesPassed, gate_violations: [] };
if (coherenceScore < qualityGates.min_coherence_score) qualityValidation.gate_violations.push('coherence_too_low');
if (accuracyScore < qualityGates.min_accuracy_score) qualityValidation.gate_violations.push('accuracy_too_low');
if (completenessScore < qualityGates.min_completeness_score) qualityValidation.gate_violations.push('completeness_too_low');
return [{ json: { ...$json, quality_validation: qualityValidation, quality_gates_passed: qualityGatesPassed } }];

const governanceChecks = { governance_approved: true, approval_chain_valid: true, policy_violations: [] };
if (!$json.lineage_trace.all_links_valid) governanceChecks.governance_approved = false;
if (!$json.quality_gates_passed) governanceChecks.governance_approved = false;
if (!governanceChecks.governance_approved) governanceChecks.policy_violations.push('lineage_or_quality_failure');
return [{ json: { ...$json, governance_check: governanceChecks, governance_compliance_passed: governanceChecks.governance_approved } }];

const validationOk = $json.lineage_trace.all_links_valid && $json.quality_gates_passed && $json.governance_compliance_passed;
const contextEngineeringPacket = {
  instance_id: 'CTX-ENG-' + Date.now(),
  artifact_family: 'context_engineering_packet',
  schema_version: '1.0.0',
  producer_workflow: 'CWF-340',
  dossier_ref: $json.dossier_id || 'DOSSIER-UNSPECIFIED',
  created_at: new Date().toISOString(),
  status: validationOk ? 'VALIDATED' : 'VALIDATION_FAILED',
  payload: {
    lineage_validated: $json.lineage_trace.all_links_valid,
    quality_gates_passed: $json.quality_gates_passed,
    governance_compliance_passed: $json.governance_compliance_passed,
    lineage_trace: $json.lineage_trace,
    quality_scores: {
      coherence: $json.quality_validation.coherence_score,
      accuracy: $json.quality_validation.accuracy_score,
      completeness: $json.quality_validation.completeness_score
    },
    next_workflow: validationOk ? 'WF-400' : 'WF-900',
    promotion_eligible: validationOk
  }
};
return [{ json: { ...$json, context_engineering_packet: contextEngineeringPacket, validation_complete: true, validation_passed: validationOk } }];

try {
  const SkillLoader = require('../../../engine/skill_loader/skill_loader.js');
  const loader = new SkillLoader();

  if (!loader.skills_registry || Object.keys(loader.skills_registry).length === 0) {
    const initResult = await loader.initialize();
    if (initResult.status !== 'initialized') {
      throw new Error('Failed to initialize SkillLoader');
    }
  }

  const workflowId = 'CWF-340';
  const defaultSkillMap = {"CWF-310":"M-001","CWF-320":"M-001","CWF-330":"M-001","CWF-340":"M-001","CWF-410":"M-001","CWF-420":"M-001","CWF-430":"M-001","CWF-440":"M-001","CWF-510":"M-001","CWF-520":"M-001","CWF-530":"M-001"};
  const skillId = $json.skill_id || defaultSkillMap[workflowId] || 'M-001';
  const dossierId = $json.dossier_context?.dossier_id || $json.dossier_id || 'DOSSIER-UNSPECIFIED';

  const contextPacket = {
    dossier_id: dossierId,
    workflow_id: workflowId,
    ...(typeof $json.user_context === 'object' ? $json.user_context : {}),
    ...(typeof $json.route_context === 'object' ? $json.route_context : {})
  };

  const dossierState = typeof $json.dossier === 'object' ? $json.dossier : {};
  const result = await loader.executeSkill(skillId, contextPacket, dossierState);

  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: workflowId,
        skill_id: skillId,
        status: result.status,
        had_error: result.status !== 'SUCCESS',
        error_message: result.status === 'SUCCESS' ? '' : String(result.error || ''),
        timestamp: new Date().toISOString()
      },
      runtime_packet: result.status === 'SUCCESS' ? (result.output || null) : null,
      skill_execution_result: result.status === 'SUCCESS' ? result : null,
      runtime: {
        had_error: result.status !== 'SUCCESS',
        error_message: result.status === 'SUCCESS' ? '' : String(result.error || '')
      }
    }
  }];
} catch (error) {
  const message = String(error && error.message ? error.message : error);
  return [{
    json: {
      ...$json,
      phase8_runtime_probe: {
        workflow_id: 'CWF-340',
        skill_id: null,
        status: 'ERROR',
        had_error: true,
        error_message: message,
        timestamp: new Date().toISOString()
      },
      runtime_packet: null,
      skill_execution_result: null,
      runtime: { had_error: true, error_message: message }
    }
  }];
}
